INSERT INTO temp_entity_assignments SELECT custpack_id AS entityid, connection_no AS entityname, 'tbltcustomerinventorymapping' AS tablename, 'Assign to Staff' AS assign_to_team_or_staff, adoptconvergebss.tblstaffuser.username as staff_name, "Inventory WorkFlow" as workflow FROM adoptinventorymanagement.tbltcustomerinventorymapping inner join adoptconvergebss.tblstaffuser on adoptinventorymanagement.tbltcustomerinventorymapping.next_approver = adoptconvergebss.tblstaffuser.staffid WHERE next_approver IS NOT NULL AND mvno_id = mvnoid LIMIT 1;
INSERT INTO temp_entity_assignments SELECT CREDITDOCID AS entityid, referenceno AS entityname, 'tbltcreditdoc' AS tablename, 'Assign to Staff' AS assign_to_team_or_staff, adoptconvergebss.tblstaffuser.username as staff_name, "CreditNote WorkFlow" as workflow FROM adoptconvergebss.tbltcreditdoc inner join adoptconvergebss.tblstaffuser on adoptconvergebss.tbltcreditdoc.APPROVEDBYSTAFFID = adoptconvergebss.tblstaffuser.staffid WHERE (APPROVEDBYSTAFFID IS NOT NULL OR next_team_hir_mapping IS NOT NULL) AND adoptconvergebss.tbltcreditdoc.MVNOID = mvnoid and paytype ="creditnote" LIMIT 1;
INSERT INTO temp_entity_assignments SELECT CREDITDOCID AS entityid, referenceno AS entityname, 'tbltcreditdoc' AS tablename, 'Assign to Staff' AS assign_to_team_or_staff, adoptconvergebss.tblstaffuser.username as staff_name, "Payment Workflow" as workflow FROM adoptconvergebss.tbltcreditdoc inner join adoptconvergebss.tblstaffuser on adoptconvergebss.tbltcreditdoc.APPROVEDBYSTAFFID = adoptconvergebss.tblstaffuser.staffid WHERE (APPROVEDBYSTAFFID IS NOT NULL OR next_team_hir_mapping IS NOT NULL) AND adoptconvergebss.tbltcreditdoc.MVNOID = mvnoid and paytype <> "creditnote" LIMIT 1;
INSERT INTO temp_entity_assignments SELECT id AS entityid, connection_no AS entityname, 'tbltcustomerservicemapping' AS tablename, 'Assign to Staff' AS assign_to_team_or_staff, adoptconvergebss.tblstaffuser.username as staff_name, "Service workflow" as workflow FROM adoptconvergebss.tbltcustomerservicemapping INNER JOIN adoptconvergebss.tblcustomers ON adoptconvergebss.tbltcustomerservicemapping.custid = adoptconvergebss.tblcustomers.custid inner join adoptconvergebss.tblstaffuser on adoptconvergebss.tbltcustomerservicemapping.next_staff = adoptconvergebss.tblstaffuser.staffid WHERE (next_staff IS NOT NULL OR adoptconvergebss.tbltcustomerservicemapping.next_team_hir_mapping IS NOT NULL) AND adoptconvergebss.tblcustomers.MVNOID = 3 and discount_flow_in_process ="no" or discount_flow_in_process = null LIMIT 1;
INSERT INTO temp_entity_assignments SELECT plangroupid AS entityid, plangroupname AS entityname, 'tblmplangroup' AS tablename, 'Assign to Staff' AS assign_to_team_or_staff, adoptconvergebss.tblstaffuser.username as staff_name, "PlanGroup WorkFlow" as workflow FROM adoptconvergebss.tblmplangroup inner join adoptconvergebss.tblstaffuser on adoptconvergebss.tblmplangroup.next_staff = adoptconvergebss.tblstaffuser.staffid WHERE (next_staff IS NOT NULL OR next_team_hir_mapping IS NOT NULL) AND adoptconvergebss.tblmplangroup.MVNOID = mvnoid LIMIT 1;
INSERT INTO temp_entity_assignments SELECT debitdocumentid AS entityid, debitdocumentnumber AS entityname, 'tbltdebitdocument' AS tablename, 'Assign to Staff' AS assign_to_team_or_staff, adoptconvergebss.tblstaffuser.username as staff_name, "Invoice WorkFlow" as workflow FROM adoptconvergebss.tbltdebitdocument inner join adoptconvergebss.tblstaffuser on adoptconvergebss.tbltdebitdocument.next_staff = adoptconvergebss.tblstaffuser.staffid INNER JOIN adoptconvergebss.tblcustomers ON adoptconvergebss.tbltdebitdocument.subscriberid = adoptconvergebss.tblcustomers.custid WHERE (next_staff IS NOT NULL OR next_team_hir_mapping_id IS NOT NULL) AND adoptconvergebss.tblcustomers.MVNOID = mvnoid LIMIT 1;
-- INSERT INTO temp_entity_assignments -- SELECT partner_id AS entityid, refno AS entityname, 'tblmpartnerpayment' AS tablename, 'Assign to Staff' AS assign_to_team_or_staff,adoptpartnermanagement.tblmstaffuser.username as staff_name, "Partner Payment" as workflow -- FROM adoptpartnermanagement.tblmpartnerpayment -- inner join adoptpartnermanagement.tblmstaffuser on adoptpartnermanagement.tblmpartnerpayment.next_staff = adoptpartnermanagement.tblmstaffuser.staffid -- INNER JOIN adoptpartnermanagement.tblpartners ON adoptpartnermanagement.tblmpartnerpayment.partner_id = adoptpartnermanagement.tblpartners.PARTNERID -- WHERE (next_staff IS NOT NULL OR next_team_hir_mapping_id IS NOT NULL) AND adoptpartnermanagement.tblpartners.MVNOID = mvnoid -- LIMIT 1;
INSERT INTO temp_entity_assignments SELECT ADDRESSID AS entityid, landmark AS entityname, 'tblmsubscriberaddressrel' AS tablename, 'Assign to Staff' AS assign_to_team_or_staff, adoptconvergebss.tblstaffuser.username as staff_name, "ShiftLocation WorkFlow" as workflow FROM adoptconvergebss.tblmsubscriberaddressrel inner join adoptconvergebss.tblstaffuser on adoptconvergebss.tblmsubscriberaddressrel.next_staff = adoptconvergebss.tblstaffuser.staffid INNER JOIN adoptconvergebss.tblcustomers ON adoptconvergebss.tblmsubscriberaddressrel.SUBSCRIBERID = adoptconvergebss.tblcustomers.custid WHERE (next_staff IS NOT NULL or adoptconvergebss.tblmsubscriberaddressrel.next_team_hir_mapping IS NOT NULL) AND adoptconvergebss.tblcustomers.MVNOID = mvnoid LIMIT 1;
INSERT INTO temp_entity_assignments SELECT doc_id AS entityid, doc_type AS entityname, 'tblcustdocdetails' AS tablename, 'Assign to Staff' AS assign_to_team_or_staff, adoptconvergebss.tblstaffuser.username as staff_name,"Document Verification WorkFlow" as workflow FROM adoptconvergebss.tblcustdocdetails INNER JOIN adoptconvergebss.tblcustomers ON adoptconvergebss.tblcustdocdetails.cust_id = adoptconvergebss.tblcustomers.custid inner join adoptconvergebss.tblstaffuser on adoptconvergebss.tblcustdocdetails.next_staff = adoptconvergebss.tblstaffuser.staffid WHERE (next_staff IS NOT NULL OR adoptconvergebss.tblcustdocdetails.next_team_hir_mapping IS NOT NULL) AND adoptconvergebss.tblcustomers.MVNOID = mvnoid LIMIT 1;
INSERT INTO temp_entity_assignments SELECT CUSTSPPLANID AS entityid, mapping_name AS entityname, 'tblmcustspecialplanrelmapping' AS tablename, 'Assign to Staff' AS assign_to_team_or_staff,adoptconvergebss.tblstaffuser.username as staff_name, "Special Plan Mapping WorkFlow" as workflow FROM adoptconvergebss.tblmcustspecialplanrelmapping inner join adoptconvergebss.tblstaffuser on adoptconvergebss.tblmcustspecialplanrelmapping.next_staff = adoptconvergebss.tblstaffuser.staffid WHERE (next_staff IS NOT NULL OR next_team_hir_mapping IS NOT NULL) AND adoptconvergebss.tblmcustspecialplanrelmapping.MVNOID = 3 LIMIT 1;
INSERT INTO temp_entity_assignments SELECT entity_id AS entityid, event_name AS entityname, 'tblworkflowassignstaffmapping' AS tablename, 'Assign to Team' AS assign_to_team_or_staff, adoptconvergebss.tblstaffuser.username as staff_name, concat(event_name,' WorkFlow') as workflow FROM adoptconvergebss.tblworkflowassignstaffmapping INNER JOIN adoptconvergebss.tblstaffuser ON adoptconvergebss.tblworkflowassignstaffmapping.staff_id = adoptconvergebss.tblstaffuser.staffid WHERE id IS NOT NULL AND adoptconvergebss.tblstaffuser.MVNOID = mvnoid LIMIT 1;
INSERT INTO temp_entity_assignments SELECT ticket_id AS entityid, 'Ticket' AS entityname, 'tblmticketassignstaffmapping' AS tablename, 'Assign to Team' AS assign_to_team_or_staff, adoptconvergebss.tblstaffuser.username as staff_name , "Ticket WorkFlow " as workflow FROM adoptticketmanagement.tblmticketassignstaffmapping INNER JOIN adoptticketmanagement.tblcases ON adoptticketmanagement.tblmticketassignstaffmapping.ticket_id = adoptticketmanagement.tblcases.case_id inner join adoptconvergebss.tblstaffuser on adoptticketmanagement.tblmticketassignstaffmapping.staff_id = adoptconvergebss.tblstaffuser.staffid WHERE id IS NOT NULL AND adoptticketmanagement.tblcases.MVNOID = mvnoid LIMIT 1;
-- Select the results from the temporary table SELECT * FROM temp_entity_assignments; END

